t = int(input())
for _ in range(t):
    n = int(input())
    if n <= 26:
        print('abcdefghijklmnopqrstuvwxyz'[:n])
    else:
        # Use 'a'*(n-25) if odd, else 'a'*(n-24), adjust
        extra = n - 25
        if extra % 2 == 0:
            extra += 1
            tail_len = n - extra
        else:
            tail_len = 25
        print('a' * extra + 'bcdefghijklmnopqrstuvwxyz'[:tail_len])
